#include <bits/stdc++.h>
using namespace std;
long long quick_mi(int a,int b,int p){
	long long ans=1,base=a;
	while(b){
		if(b&1)
			ans*=base,ans%=p;
		base*=base,base%=p,b>>=1;
	}
	return ans;
}
long long c[1003][1003];
long long fact(int n,int m){
	for(int i=0;i<=n;i++)
		for(int j=0;j<=i;j++)
			c[i][j]=(j==0 || j==i? 1:c[i-1][j-1]+c[i-1][j]),c[i][j]%=10007;
	return c[n][m];
}
int main(){
	int a,b,k,n,m;
	scanf("%d%d%d%d%d",&a,&b,&k,&n,&m);
	printf("%lld",1LL*quick_mi(a,n,10007)*quick_mi(b,m,10007)*fact(k,n)%10007);
	return 0;
}
